        "html"
    ).toLowerCase().trim();

    const allowed = ["lovelace", "html", "both", "disabled"];
    return allowed.includes(raw) ? raw : "html";
}
function wantsLovelace() {
    const mode = getPremiumDashboardOutput();
    return mode === "lovelace" || mode === "both";
}
function wantsHtml() {
    const mode = getPremiumDashboardOutput();
    return mode === "html" || mode === "both";
}

