        chart_type: "donut",
        header: {
            show: true,
            title,
            show_states: true,
            colorize_states: true,
            standard_format: true,
            floating: false
        },
        all_series_config: {
            float_precision: 2,
            show: {
                in_header: true,
                legend_value: true
            }
        },
        series,
        apex_config: {
            chart: {
                height
