.app{padding:10px;min-height:100vh}.topbar{display:flex;justify-content:space-between;align-items:center;gap:12px;flex-wrap:wrap;margin-bottom:10px}.title-main{display:flex;gap:10px;align-items:center;flex-wrap:wrap}.title-main h1{margin:0;font-size:28px}.pill{padding:9px 13px;border-radius:999px;background:rgba(15,25,45,.9);border:1px solid var(--border);font-weight:900;font-size:13px}.ok{color:#baffcf;border-color:rgba(36,224,109,.35);background:rgba(36,224,109,.13)}.refresh{background:linear-gradient(135deg,rgba(46,199,255,.34),rgba(36,224,109,.20));border-color:rgba(46,199,255,.70);color:#ffffff;box-shadow:0 0 22px rgba(46,199,255,.18)}.refresh:hover{filter:brightness(1.15);box-shadow:0 0 28px rgba(46,199,255,.32)}.premium{color:#ffd7a6;border-color:rgba(255,159,67,.48);background:rgba(255,159,67,.16)}
.tabs{display:flex;gap:8px;flex-wrap:wrap;margin-bottom:10px}.tab{border:1px solid var(--border);background:rgba(15,25,45,.82);color:#dbeafe;padding:11px 16px;border-radius:14px;font-weight:1000;cursor:pointer}.tab.active{background:rgba(46,199,255,.20);border-color:rgba(46,199,255,.65);color:#fff}
.view{display:none}.view.active{display:block}.panel{background:var(--panel);border:1px solid var(--border);border-radius:18px;padding:12px;box-shadow:0 20px 70px rgba(0,0,0,.36);margin-bottom:10px}.section-title{font-size:20px;font-weight:1000;text-transform:uppercase;margin:0 0 10px;display:flex;align-items:center;gap:10px}.live{font-size:11px;color:#7cffad;background:rgba(36,224,109,.14);border:1px solid rgba(36,224,109,.33);padding:4px 8px;border-radius:999px}
.cards4{display:grid;grid-template-columns:repeat(4,1fr);gap:10px}.cards3{display:grid;grid-template-columns:repeat(3,1fr);gap:10px}.cards2{display:grid;grid-template-columns:repeat(2,1fr);gap:10px}.dash-grid{display:grid;grid-template-columns:1fr 1fr;gap:10px}
.card{background:var(--card);border:1px solid var(--border);border-radius:14px;padding:12px;box-shadow:0 12px 35px rgba(0,0,0,.25)}.label{color:var(--muted);font-size:10px;font-weight:1000;text-transform:uppercase;letter-spacing:1.2px}.value{font-size:25px;font-weight:1000;letter-spacing:-1px;margin-top:5px}.small{color:var(--muted);font-size:11px;margin-top:4px}.bat{border-color:rgba(36,224,109,.55)}.load{border-color:rgba(46,199,255,.55)}.gridc{border-color:rgba(155,92,255,.55)}.solar{border-color:rgba(255,201,40,.55)}.red{border-color:rgba(255,95,122,.55)}.orange{border-color:rgba(255,159,67,.55)}
.donut-row{display:grid;grid-template-columns:280px 1fr;gap:18px;align-items:center}.donut{width:250px;height:250px;min-width:250px;border-radius:50%;margin:auto;display:flex;align-items:center;justify-content:center;background:conic-gradient(var(--solar) 0 35%,var(--bat) 35% 70%,var(--grid) 70% 100%);box-shadow:0 0 45px rgba(46,199,255,.13)}.donut-inner{width:155px;height:155px;border-radius:50%;background:#0f172a;display:flex;align-items:center;justify-content:center;text-align:center;border:1px solid rgba(126,161,206,.18)}
.donut{position:relative;overflow:visible}.donut-label{display:none!important}.donut-label{position:absolute;z-index:4;min-width:76px;padding:5px 7px;border-radius:10px;background:rgba(2,6,23,.92);border:1px solid rgba(126,161,206,.28);box-shadow:0 10px 28px rgba(0,0,0,.35);font-size:10px;font-weight:1000;line-height:1.15;text-align:center;white-space:nowrap}.donut-label b{display:block;color:#fff;font-size:12px}.donut-label small{display:block;color:#91a7c4;font-size:9px;text-transform:uppercase;letter-spacing:.4px}.donut-label.top{left:50%;top:-24px;transform:translateX(-50%)}.donut-label.left{left:-20px;top:50%;transform:translate(-50%,-50%)}.donut-label.right{right:-20px;top:50%;transform:translate(50%,-50%)}.donut-label.bottom{left:50%;bottom:-24px;transform:translateX(-50%)}
.legend{display:grid;gap:8px}.legend-line{display:flex;justify-content:space-between;gap:10px;border-bottom:1px solid rgba(126,161,206,.12);padding-bottom:7px;font-weight:900}.dot{display:inline-block;width:11px;height:11px;border-radius:50%;margin-right:8px}
.chart-tabs{display:flex;gap:8px;flex-wrap:wrap;margin:10px 0}.chart-tab{padding:8px 12px;border-radius:999px;border:1px solid var(--border);background:#0f172a;color:#cbd5e1;font-weight:900;cursor:pointer}.chart-tab.active{background:rgba(56,189,248,.18);border-color:rgba(56,189,248,.55);color:#fff}.svg-chart{width:100%;height:310px;border-radius:16px;background:#06101d;border:1px solid rgba(126,161,206,.18);overflow:hidden}.chart-legend{display:flex;justify-content:flex-end;gap:16px;color:#dbeafe;font-size:12px;font-weight:900;margin-bottom:8px}
.history-tooltip{position:fixed;z-index:999999;display:none;pointer-events:none;border-radius:12px;padding:10px 12px;font-size:12px;font-weight:1000;box-shadow:0 18px 55px rgba(0,0,0,.48);border:1px solid rgba(255,255,255,.30);color:#fff;min-width:190px}.history-tooltip.dark{color:#06101d}.history-tooltip .muted{opacity:.82;font-weight:900}.hist-hit{cursor:crosshair}.correction-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:10px}.field{background:rgba(9,18,34,.76);border:1px solid rgba(126,161,206,.16);border-radius:14px;padding:10px}.field label{display:block;color:#91a7c4;font-size:11px;font-weight:1000;text-transform:uppercase;margin-bottom:6px}.field input{width:100%;background:#0f172a;color:#fff;border:1px solid rgba(126,161,206,.28);border-radius:10px;padding:10px;font-weight:900}.actions{display:flex;gap:8px;flex-wrap:wrap;margin-top:10px}.btn{border:0;border-radius:12px;background:rgba(46,199,255,.24);color:white;font-weight:1000;padding:10px 14px;cursor:pointer}.btn.red{background:rgba(255,95,122,.22)}
@media(max-width:1100px){.cards4,.cards3,.dash-grid,.correction-grid{grid-template-columns:1fr 1fr}.donut-row{grid-template-columns:1fr}.donut{width:210px;height:210px;min-width:210px}.donut-inner{width:130px;height:130px}}
@media(max-width:620px){.cards4,.cards3,.cards2,.dash-grid,.correction-grid{grid-template-columns:1fr}.title-main h1{font-size:23px}.donut{width:180px;height:180px;min-width:180px}.donut-inner{width:112px;height:112px}}
</style>
</head>
<body>
<div class="app">
  <div class="topbar">
    <div class="title-main"><h1>Smart Energy Finance</h1><span class="pill premium">PREMIUM</span><span class="pill ok">● <span id="ha_status">Connexion...</span></span><span class="pill" id="clock">--:--:--</span></div>
    <div class="title-main"><span class="pill">💶 <span id="active_tariff">--</span></span><span class="pill">€/kWh <span id="active_price">--</span></span><button class="pill refresh" onclick="location.reload()">↻ Rafraîchir</button></div>
  </div>

  <div class="tabs">
    <button class="tab active" onclick="showView('finance',this)">💶 Finance</button>
    <button class="tab" onclick="showView('correction',this)">🛠️ Correction</button>
  </div>

  <section id="finance" class="view active">
    <div class="panel">
      <div class="section-title">💶 Économie <span class="live">Analyse économique premium</span></div>
      <div class="cards4">
        <div class="card bat"><div class="label">Économie jour</div><div class="value"><span id="day_savings">--</span> €</div><div class="small">vs sans solaire</div></div>
        <div class="card load"><div class="label">Économie mois</div><div class="value"><span id="month_savings">--</span> €</div><div class="small">cumul mensuel</div></div>
        <div class="card gridc"><div class="label">Économie année</div><div class="value"><span id="year_savings">--</span> €</div><div class="small">cumul annuel</div></div>
        <div class="card orange"><div class="label">Batterie jour</div><div class="value"><span id="battery_day_savings">--</span> €</div><div class="small">économie batterie</div></div>
      </div>
    </div>

    <div class="dash-grid">
      <div class="panel">
        <div class="section-title">💶 Répartition économique jour</div>
        <div class="donut-row">
          <div id="donut_day" class="donut"><div class="donut-inner"><div><div class="value"><span id="day_total">--</span> €</div><div class="small">Total</div></div></div></div>
          <div class="legend">
            <div class="legend-line"><span><i class="dot" style="background:#ef4444"></i>Coût import</span><b><span id="day_import_cost">--</span> €</b></div>
            <div class="legend-line"><span><i class="dot" style="background:#22c55e"></i>Revenu export</span><b><span id="day_export_revenue">--</span> €</b></div>
            <div class="legend-line"><span><i class="dot" style="background:#ffc928"></i>Valeur solaire</span><b><span id="day_solar_value">--</span> €</b></div>
            <div class="legend-line"><span><i class="dot" style="background:#24e06d"></i>Éco batterie</span><b><span id="day_battery_value">--</span> €</b></div>
            <div class="legend-line"><span><i class="dot" style="background:#9b5cff"></i>Abonnement</span><b><span id="day_subscription">--</span> €</b></div>
          </div>
        </div>
      </div>

      <div class="panel">
        <div class="section-title">📅 Mois / Année</div>
        <div class="cards2">
          <div class="card"><div class="label">Répartition mois</div><div id="donut_month" class="donut"><div class="donut-inner"><div><div class="value"><span id="month_total">--</span> €</div><div class="small">mois</div></div></div></div></div>
          <div class="card"><div class="label">Répartition année</div><div id="donut_year" class="donut"><div class="donut-inner"><div><div class="value"><span id="year_total">--</span> €</div><div class="small">année</div></div></div></div></div>
        </div>
      </div>
    </div>

    <div class="panel">
      <div class="section-title">📈 Statistiques économie <span class="live">Historique</span></div>
      <div class="cards2">
        <div class="card bat"><div class="label">Économie totale aujourd'hui</div><div class="value"><span id="hero_day">--</span> €</div><div class="small">Solaire + batterie vs achat réseau</div></div>
      </div>
      <div class="chart-tabs">
        <button class="chart-tab active" onclick="setPeriod('daily',this)">30 jours</button>
        <button class="chart-tab" onclick="setPeriod('monthly',this)">12 mois</button>
        <button class="chart-tab" onclick="setPeriod('yearly',this)">10 ans</button>
      </div>
      <div class="chart-legend"><span><i class="dot" style="background:#ffc928"></i>Solaire</span><span><i class="dot" style="background:#24e06d"></i>Batterie</span><span><i class="dot" style="background:#38bdf8"></i>Total économie</span></div>
      <div id="history_tooltip" class="history-tooltip"></div>
      <div id="history_chart" class="svg-chart"></div>
    </div>

    <div class="panel">
      <div class="section-title">⚡ Énergie jour</div>
      <div class="cards4">
        <div class="card solar"><div class="label">Solaire</div><div class="value"><span id="day_solar_kwh">--</span> kWh</div></div>
        <div class="card load"><div class="label">Maison</div><div class="value"><span id="day_load_kwh">--</span> kWh</div></div>
        <div class="card gridc"><div class="label">Import réseau</div><div class="value"><span id="day_grid_import">--</span> kWh</div></div>
        <div class="card bat"><div class="label">Décharge batterie</div><div class="value"><span id="battery_day_discharge">--</span> kWh</div></div>
      </div>
    </div>
  </section>

  <section id="correction" class="view">
    <div class="panel">
      <div class="section-title">🛠️ Correction <span class="live">Rafraîchissement 30 s</span></div>
      <div class="correction-grid" id="correction_fields"></div>
      <div class="actions">
        <button class="btn" onclick="callService('button','press','button.smart_energy_finance_apply_correction')">OK / Appliquer</button>
        <button class="btn" onclick="callService('button','press','button.smart_energy_finance_clear_correction')">Effacer les champs</button>
        <button class="btn red" onclick="callService('button','press','button.smart_energy_finance_reset_day_counters')">Reset journée</button>
        <button class="btn red" onclick="callService('button','press','button.smart_energy_finance_restore_day_backup')">Restore backup journée</button>
        <button class="btn red" onclick="callService('button','press','button.smart_energy_finance_reset_all_counters')">Reset all</button>
      </div>
    </div>
  </section>
</div>

<script>
var STATES = {};
var PERIOD = "daily";
var CORRECTION_ENTITIES = [
 ["correction_date","Date"],["correction_solar_kwh","Solar kWh"],["correction_load_kwh","Load kWh"],["correction_grid_import_kwh","Grid import kWh"],["correction_grid_export_kwh","Grid export kWh"],["correction_battery_charge_kwh","Battery charge kWh"],["correction_battery_discharge_kwh","Battery discharge kWh"],["correction_import_cost","Import cost"],["correction_export_revenue","Export revenue"],["correction_solar_production_value","Solar value"],["correction_battery_discharge_value","Battery value"],["correction_home_supply_savings","Home supply savings"],["correction_theoretical_no_solar_cost","No solar cost"],["correction_real_total_with_subscription","Real total"],["correction_savings_vs_no_solar","Savings vs no solar"],["confirmation_reset_all","Confirm reset all"]
];

function $(id){return document.getElementById(id)}
function ent(s){return "sensor.smart_energy_finance_" + s}
function textEnt(s){return "text.smart_energy_finance_" + s}
function st(id){return STATES[id] ? STATES[id].state : undefined}
function at(id){return STATES[id] ? (STATES[id].attributes || {}) : {}}
function num(v){var x=Number(String(v===undefined||v===null?0:v).replace(",","."));return Number.isFinite(x)?x:0}
function fmt(v,d){return num(v).toFixed(d===undefined?2:d)}
function set(id,v){var e=$(id); if(e) e.textContent = v}
function val(s){return num(st(ent(s)))}
function money(s){return fmt(val(s),2)}
function kwh(s){return fmt(val(s),2)}
function getHass(){
  var wins=[window];
  try{wins.push(window.parent)}catch(e){}
  try{wins.push(window.parent.parent)}catch(e){}
  try{wins.push(window.top)}catch(e){}
  for(var i=0;i<wins.length;i++){
    try{
      var w=wins[i];
      if(w && w.hass && w.hass.states) return w.hass;
      var ha=w.document && w.document.querySelector && w.document.querySelector("home-assistant");
      if(ha && ha.hass && ha.hass.states) return ha.hass;
    }catch(e){}
  }
  return null;
}
window.addEventListener("message",function(ev){
  if(ev.data && ev.data.type==="SEF_HASS_STATES"){
    STATES=ev.data.states || {};
    updateFinance();
  }
});
function showView(id,btn){
  document.querySelectorAll(".view").forEach(function(v){v.classList.remove("active")});
  document.querySelectorAll(".tab").forEach(function(t){t.classList.remove("active")});
  $(id).classList.add("active"); btn.classList.add("active");
  if(id==="correction") updateCorrection();
}
function setPeriod(p,btn){PERIOD=p;document.querySelectorAll(".chart-tab").forEach(function(t){t.classList.remove("active")});btn.classList.add("active");renderHistory()}
function cssDonut(id,items){
  var el=$(id); if(!el) return;
  var total=items.reduce(function(a,x){return a+Math.max(0,num(x.v))},0);
  if(total<=0){el.style.background="conic-gradient(rgba(126,161,206,.22) 0deg 360deg)";return}
  var deg=0,parts=[];
  items.forEach(function(it){var v=Math.max(0,num(it.v));var next=deg+(v/total)*360;parts.push(it.c+" "+deg+"deg "+next+"deg");deg=next});
  el.style.background="conic-gradient("+parts.join(",")+")";
}
function donutLabels(id,items){
  var el=$(id); if(!el) return;
  el.querySelectorAll(".donut-label").forEach(function(x){x.remove()});
  var pos=["top","right","left","bottom"];
  items.filter(function(it){return Math.abs(num(it.v))>0.005}).slice(0,4).forEach(function(it,i){
    var d=document.createElement("div");
    d.className="donut-label "+(it.pos||pos[i]||"top");
    d.style.borderColor=it.c||"rgba(126,161,206,.28)";
    d.innerHTML="<b>"+fmt(it.v,2)+" €</b><small>"+it.label+"</small>";
    el.appendChild(d);
  });
}
function extractRows(kind){
  var a=at(ent("history_archive"));
  var candidates=[a[kind], a["history_"+kind], a[kind+"_history"], a.archive_json, a.history_json, a.history];
  for(var i=0;i<candidates.length;i++){
    var r=candidates[i];
    if(typeof r==="string"){try{r=JSON.parse(r)}catch(e){r=[]}}
    if(r && !Array.isArray(r) && typeof r==="object"){
      if(Array.isArray(r[kind])) r=r[kind];
      else if(Array.isArray(r.daily) && kind==="daily") r=r.daily;
      else if(Array.isArray(r.monthly) && kind==="monthly") r=r.monthly;
      else if(Array.isArray(r.yearly) && kind==="yearly") r=r.yearly;
    }
    if(Array.isArray(r) && r.length) return r;
  }
  return [];
}
function renderMonthSplit(){
  var rows=extractRows("daily");
  var now=new Date();
  var mk=now.getFullYear()+"-"+String(now.getMonth()+1).padStart(2,"0");
  var month=rows.filter(function(r){return String(r.key||"").slice(0,7)===mk});
  var solar=month.reduce(function(a,r){return a+num(r.solar_production_value)},0);
  var bat=month.reduce(function(a,r){return a+num(r.battery_discharge_value)},0);
  var total=month.reduce(function(a,r){return a+num(r.savings_vs_no_solar)},0);
  $("month_split").innerHTML = '<div class="legend-line"><span>Solaire</span><b>'+fmt(solar,2)+' €</b></div><div class="legend-line"><span>Batterie</span><b>'+fmt(bat,2)+' €</b></div><div class="legend-line"><span>Total</span><b>'+fmt(total,2)+' €</b></div>';
}
function historyLabel(key){
  key=String(key||"");
  if(PERIOD==="daily"){
    var p=key.split("-");
    return p.length===3 ? p[2]+"/"+p[1] : key;
  }
  if(PERIOD==="monthly"){
    var m=key.split("-");
    return m.length>=2 ? m[1]+"/"+String(m[0]).slice(2) : key;
  }
  return key;
}
function escAttr(s){return String(s||"").replace(/&/g,"&amp;").replace(/\"/g,"&quot;").replace(/</g,"&lt;").replace(/>/g,"&gt;")}
function showHistTip(ev, html, color){
  var tip=$("history_tooltip"); if(!tip) return;
  tip.innerHTML=html;
  tip.style.background=color||"#0f172a";
  tip.className="history-tooltip"+((color==="#ffc928"||color==="#24e06d")?" dark":"");
  tip.style.display="block";
  var x=ev.clientX+14, y=ev.clientY+14;
  tip.style.left=x+"px"; tip.style.top=y+"px";
}
function hideHistTip(){var tip=$("history_tooltip"); if(tip) tip.style.display="none"}
function bindHistoryHover(){
  document.querySelectorAll("#history_chart .hist-hit").forEach(function(el){
    el.addEventListener("mousemove",function(ev){showHistTip(ev, el.getAttribute("data-tip"), el.getAttribute("data-color"));});
    el.addEventListener("mouseleave",hideHistTip);
  });
}
function renderHistory(){
  var rows=extractRows(PERIOD);
  if(PERIOD==="daily") rows=rows.slice(-30);
  if(PERIOD==="monthly") rows=rows.slice(-12);
  if(PERIOD==="yearly") rows=rows.slice(-10);
  var el=$("history_chart"); if(!el) return;
  if(!rows.length){el.innerHTML='<div style="padding:30px;color:#91a7c4;font-weight:900">Historique en attente sur sensor.smart_energy_finance_history_archive</div>';return}
  var w=1180,h=335,p=46;
  var max=1;
  rows.forEach(function(r){
    var total=num(r.savings_vs_no_solar);
    var bat=num(r.battery_discharge_value);
    var solar=Math.max(0,total-bat);
    max=Math.max(max, solar+bat, total);
  });
  max=max*1.22;
  var step=(w-p*2)/rows.length;
  var bw=Math.max(10,Math.min(42,step*0.58));
  var linePts=[];
  var svg='<svg viewBox="0 0 '+w+' '+h+'" width="100%" height="100%" role="img">';
  svg+='<line x1="'+p+'" y1="'+(h-p)+'" x2="'+(w-p)+'" y2="'+(h-p)+'" stroke="rgba(126,161,206,.35)"/>';
  rows.forEach(function(r,i){
    var key=String(r.key||'');
    var label=historyLabel(key);
    var x=p+i*step+(step-bw)/2;
    var total=num(r.savings_vs_no_solar);
    var bat=num(r.battery_discharge_value);
    var solar=Math.max(0,total-bat);
    var sh=(h-p*2)*(solar/max), bh=(h-p*2)*(bat/max), th=(h-p*2)*(total/max);
    var base=h-p;
    var ySolar=base-sh, yBat=ySolar-bh;
    var cx=x+bw/2, cy=base-th;
    var tip='<div>'+escAttr(key)+'</div><div class="muted">Solaire : '+fmt(solar,2)+' €</div><div class="muted">Batterie : '+fmt(bat,2)+' €</div><div>Total économie : '+fmt(total,2)+' €</div>';
    var tipAttr=escAttr(tip);
    svg+='<rect class="hist-hit" data-color="#ffc928" data-tip="'+tipAttr+'" x="'+x.toFixed(1)+'" y="'+ySolar.toFixed(1)+'" width="'+bw.toFixed(1)+'" height="'+Math.max(1,sh).toFixed(1)+'" rx="5" fill="#ffc928"></rect>';
    svg+='<rect class="hist-hit" data-color="#24e06d" data-tip="'+tipAttr+'" x="'+x.toFixed(1)+'" y="'+yBat.toFixed(1)+'" width="'+bw.toFixed(1)+'" height="'+Math.max(1,bh).toFixed(1)+'" rx="5" fill="#24e06d"></rect>';
    svg+='<text x="'+cx.toFixed(1)+'" y="'+Math.max(14,yBat-8).toFixed(1)+'" text-anchor="middle" fill="#edf5ff" font-size="11" font-weight="900">'+fmt(total,2)+'€</text>';
    linePts.push(cx.toFixed(1)+','+cy.toFixed(1));
    svg+='<circle class="hist-hit" data-color="#38bdf8" data-tip="'+tipAttr+'" cx="'+cx.toFixed(1)+'" cy="'+cy.toFixed(1)+'" r="4" fill="#38bdf8"></circle>';
