  ]);
  cssDonut("donut_year",[
    {v:solarYearPart,c:"#ffc928"},
    {v:batteryYear,c:"#24e06d"},
    {v:year,c:"#38bdf8"}
  ]);
  donutLabels("donut_year",[
    {label:"Solaire",v:solarYearPart,c:"#ffc928",pos:"top"},
    {label:"Batterie",v:batteryYear,c:"#24e06d",pos:"right"},
    {label:"Total",v:year,c:"#38bdf8",pos:"left"}
  ]);
  renderHistory();
}
function buildCorrection(){
  var box=$("correction_fields"); if(!box) return;
  box.innerHTML=CORRECTION_ENTITIES.map(function(e){
    var id=textEnt(e[0]);
    return '<div class="field"><label>'+e[1]+'</label><input id="input_'+e[0]+'" data-entity="'+id+'" value=""></div>';
  }).join("");
}
function updateCorrection(){
  CORRECTION_ENTITIES.forEach(function(e){
    var input=$("input_"+e[0]); if(input && STATES[textEnt(e[0])]) input.value=String(STATES[textEnt(e[0])].state||"");
  });
}
async function callService(domain,service,entityId,value){
  var hass=getHass();
  if(!hass || !hass.callService){alert("Home Assistant non connecté");return}
  var data={entity_id:entityId};
  if(domain==="text" && service==="set_value") data.value=value;
  await hass.callService(domain,service,data);
  setTimeout(fetchStates,800);
}
document.addEventListener("change",function(ev){
  var input=ev.target;
  if(input && input.dataset && input.dataset.entity) callService("text","set_value",input.dataset.entity,input.value);
});
function fetchStates(){
  var hass=getHass();
  if(hass && hass.states){STATES=hass.states; updateFinance(); if($("correction").classList.contains("active")) updateCorrection(); return}
  set("ha_status","HA non connecté");
  try{window.parent.postMessage({type:"SEF_REQUEST_HASS_STATES"},"*")}catch(e){}
}
function tick(){set("clock",new Date().toLocaleTimeString("fr-FR"))}
buildCorrection(); tick(); setInterval(tick,1000); fetchStates(); setInterval(fetchStates,10000); setInterval(function(){if($("correction").classList.contains("active")) updateCorrection()},30000);
</script>

<script id="SEF_V47_INDEX_LOGIC_PATCH">
(function(){
  if(window.__SEF_V47_INDEX_LOGIC_PATCH__) return;
  window.__SEF_V47_INDEX_LOGIC_PATCH__ = true;

  function q(id){ return document.getElementById(id); }
  function n(v){ var x=parseFloat(String(v==null?'0':v).replace(',','.').replace(/[^0-9.+-]/g,'')); return Number.isFinite(x)?x:0; }
  function bad(v){ return v==null || ['unknown','unavailable','none',''].indexOf(String(v).toLowerCase())>=0; }
  function s(id){ try{return (window.STATES||{})[id];}catch(e){return null;} }
  function state(id){ var x=s(id); return x && !bad(x.state) ? x.state : 0; }
  function ecoVal(id){ return n(state(id)); }
  function setTxt(id,v){ var e=q(id); if(e)e.textContent=String(v); }
  function fmt(v,d){ return n(v).toFixed(d==null?2:d); }
  function dayOfMonth(){ return new Date().getDate(); }
  function monthOfYear(){ return new Date().getMonth()+1; }
  function pad(v){ return String(v).padStart(2,'0'); }
  function dayKey(d){ return d.getFullYear()+'-'+pad(d.getMonth()+1)+'-'+pad(d.getDate()); }
  function monthKey(d){ return d.getFullYear()+'-'+pad(d.getMonth()+1); }
  function yearKey(d){ return String(d.getFullYear()); }
  function monthLabel(k){ var m=String(k||'').match(/^(\d{4})-(\d{2})/); return m ? (m[2]+'/'+m[1].slice(2)) : String(k||''); }
  function dayLabel(k){ var m=String(k||'').match(/^\d{4}-(\d{2})-(\d{2})/); return m ? m[2] : String(k||''); }
  function labelFor(period,k){ if(period==='daily') return dayLabel(k); if(period==='monthly') return monthLabel(k); return String(k||''); }
  function attrs(){ var x=s('sensor.smart_energy_finance_history_archive'); return x && x.attributes ? x.attributes : {}; }
  function normalize(raw){
    if(Array.isArray(raw)) return raw;
    if(typeof raw==='string'){
      try{ var p=JSON.parse(raw); return Array.isArray(p)?p:[]; }catch(e){ return []; }
    }
    return [];
  }
  function archiveArr(period){
    var a=attrs();
    var aliases={daily:['daily','day','days'],monthly:['monthly','month','months'],yearly:['yearly','year','years']};
    var list=aliases[period]||[period];
    for(var i=0;i<list.length;i++){
      var arr=normalize(a[list[i]]);
      if(arr.length) return arr;
    }
    return [];
  }
  function itemNumber(item,names){
    for(var i=0;i<names.length;i++){
      var name=names[i];
      if(item && item[name]!==undefined && item[name]!==null && item[name]!=='' && !bad(item[name])) return n(item[name]);
    }
    return 0;
  }
  function archiveValue(item,kind){
    var total=itemNumber(item,['savings_vs_no_solar','total_savings','savings','home_supply_savings','value','total']);
    var battery=itemNumber(item,['battery_discharge_value','battery_savings','battery_value','battery']);
    var solarFromSavings=itemNumber(item,['solar_savings_part']);
    var solar=Math.max(0, solarFromSavings || (total - battery));
    if(kind==='battery') return battery;
    if(kind==='solar') return solar;
    return Math.max(0,total || (solar+battery));
  }
  function liveEcoFallback(period,key){
    var now=new Date();
    var isCurrent=(period==='daily' && key===dayKey(now)) || (period==='monthly' && key===monthKey(now)) || (period==='yearly' && key===yearKey(now));
    if(!isCurrent) return null;
    if(period==='daily'){
      var total=ecoVal('sensor.smart_energy_finance_day_savings_vs_no_solar');
      var battery=ecoVal('sensor.smart_energy_finance_battery_day_savings') || ecoVal('sensor.smart_energy_finance_battery_day_discharge_value');
      var solar=Math.max(0,total-battery);
      return {solar:solar,battery:battery,total:total || solar+battery};
    }
    if(period==='monthly'){
      var totalM=ecoVal('sensor.smart_energy_finance_month_savings_vs_no_solar');
      var batteryM=ecoVal('sensor.smart_energy_finance_battery_month_savings') || ecoVal('sensor.smart_energy_finance_battery_month_discharge_value');
      var solarM=Math.max(0,totalM-batteryM);
      return {solar:solarM,battery:batteryM,total:totalM || solarM+batteryM};
    }
    var totalY=ecoVal('sensor.smart_energy_finance_year_savings_vs_no_solar');
    var batteryY=ecoVal('sensor.smart_energy_finance_battery_year_savings') || ecoVal('sensor.smart_energy_finance_battery_year_discharge_value');
    var solarY=Math.max(0,totalY-batteryY);
    return {solar:solarY,battery:batteryY,total:totalY || solarY+batteryY};
  }
  function buildArchiveSeries(period,count){
    var arr=archiveArr(period), map={};
    arr.forEach(function(it){ if(it && it.key) map[String(it.key)] = it; });
    var now=new Date(), out=[];
    for(var i=count-1;i>=0;i--){
      var d,key,label;
      if(period==='daily'){
        d=new Date(now); d.setHours(0,0,0,0); d.setDate(d.getDate()-i); key=dayKey(d); label=dayLabel(key);
      } else if(period==='monthly'){
        d=new Date(now.getFullYear(),now.getMonth()-i,1); key=monthKey(d); label=monthLabel(key);
      } else {
        d=new Date(now.getFullYear()-i,0,1); key=yearKey(d); label=key;
      }
      var it=map[key]||{};
      var solar=archiveValue(it,'solar'), battery=archiveValue(it,'battery'), total=archiveValue(it,'total');
      var live=liveEcoFallback(period,key);
      if(live && (!total || total<=0)){ solar=live.solar; battery=live.battery; total=live.total; }
      out.push({key:key,label:label,solar:solar,battery:battery,total:Math.max(0,total || (solar+battery))});
    }
    return out;
  }
  function setEcoDonut(id,vals){
    var e=q(id); if(!e) return;
    var total=vals.reduce(function(a,b){return a+Math.max(0,n(b));},0)||1;
    var colors=['#ef4444','#22c55e','#ffc928','#24e06d','#9b5cff'];
    var acc=0;
    var parts=vals.map(function(v,i){
      var start=acc/total*100; acc+=Math.max(0,n(v)); var end=acc/total*100;
      return colors[i]+' '+start+'% '+end+'%';
    }).join(',');
    e.style.background='conic-gradient('+parts+')';
  }
  function removeDonutRects(){ document.querySelectorAll('.donut-label').forEach(function(x){x.remove();}); }

  window.renderMonthSplit=function(){
    var m=q('month_split');
    if(m){
      var card=m.closest ? m.closest('.card') : null;
      if(card) card.remove();
      else m.innerHTML='';
    }
  };

  window.renderHistory=function(){
    var period=window.PERIOD || 'daily';
    var count=period==='daily'?30:(period==='monthly'?12:10);
    var rows=buildArchiveSeries(period,count);
    var el=q('history_chart'); if(!el) return;
    if(!rows.length){el.innerHTML='<div style="padding:30px;color:#91a7c4;font-weight:900">Historique en attente sur sensor.smart_energy_finance_history_archive</div>';return;}
    var w=1180,h=335,p=46,top=26,base=h-p,plotH=base-top,plotW=w-p*2;
    var max=Math.max.apply(null, rows.map(function(d){return Math.max(d.total,d.solar+d.battery);}));
    max=Math.max(1,max)*1.18;
    var step=plotW/(rows.length||1);
    var bw=Math.max(10,Math.min(42,step*0.58));
    var linePts=[];
    var svg='<svg viewBox="0 0 '+w+' '+h+'" width="100%" height="100%" role="img">';
    svg+='<line x1="'+p+'" y1="'+base+'" x2="'+(w-p)+'" y2="'+base+'" stroke="rgba(126,161,206,.35)"/>';
    var ticks=[0,.25,.5,.75,1];
    ticks.forEach(function(t){
      var y=top+plotH*t; var v=max/1.18*(1-t);
      svg+='<line x1="'+p+'" y1="'+y.toFixed(1)+'" x2="'+(w-p)+'" y2="'+y.toFixed(1)+'" stroke="rgba(126,161,206,.11)"/>';
      if(t<1) svg+='<text x="'+(p-8)+'" y="'+(y+4).toFixed(1)+'" text-anchor="end" fill="#91a7c4" font-size="11" font-weight="800">'+fmt(v,0)+'€</text>';
    });
    rows.forEach(function(r,i){
      var x=p+i*step+(step-bw)/2;
      var sh=plotH*(r.solar/max), bh=plotH*(r.battery/max), th=plotH*(r.total/max);
      var ySolar=base-sh, yBat=ySolar-bh;
      var cx=x+bw/2, cy=base-th;
      var label=labelFor(period,r.key);
      var tip=String(r.key)+' | Solaire '+fmt(r.solar,2)+' € | Batterie '+fmt(r.battery,2)+' € | Total '+fmt(r.total,2)+' €';
      svg+='<rect x="'+x.toFixed(1)+'" y="'+ySolar.toFixed(1)+'" width="'+bw.toFixed(1)+'" height="'+Math.max(1,sh).toFixed(1)+'" rx="5" fill="#ffc928"><title>'+tip+'</title></rect>';
      svg+='<rect x="'+x.toFixed(1)+'" y="'+yBat.toFixed(1)+'" width="'+bw.toFixed(1)+'" height="'+Math.max(1,bh).toFixed(1)+'" rx="5" fill="#24e06d"><title>'+tip+'</title></rect>';
      svg+='<rect x="'+(x-4).toFixed(1)+'" y="'+top+'" width="'+(bw+8).toFixed(1)+'" height="'+plotH+'" fill="transparent"><title>'+tip+'</title></rect>';
      svg+='<text x="'+cx.toFixed(1)+'" y="'+Math.max(14,yBat-8).toFixed(1)+'" text-anchor="middle" fill="#edf5ff" font-size="11" font-weight="900">'+fmt(r.total,2)+'€</text>';
      svg+='<text x="'+cx.toFixed(1)+'" y="'+(h-14)+'" text-anchor="middle" fill="#91a7c4" font-size="10" font-weight="800">'+label+'</text>';
      linePts.push(cx.toFixed(1)+','+cy.toFixed(1));
      svg+='<circle cx="'+cx.toFixed(1)+'" cy="'+cy.toFixed(1)+'" r="4" fill="#38bdf8"><title>'+tip+'</title></circle>';
    });
    if(linePts.length>1) svg+='<polyline points="'+linePts.join(' ')+'" fill="none" stroke="#38bdf8" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"/>';
    svg+='</svg>';
    el.innerHTML=svg;
  };

  var oldUpdate=window.updateFinance;
  window.updateFinance=function(){
    var r=typeof oldUpdate==='function'?oldUpdate.apply(this,arguments):undefined;
    removeDonutRects();

    var day=ecoVal('sensor.smart_energy_finance_day_savings_vs_no_solar');
    var month=ecoVal('sensor.smart_energy_finance_month_savings_vs_no_solar');
    var year=ecoVal('sensor.smart_energy_finance_year_savings_vs_no_solar');
    var batteryDay=ecoVal('sensor.smart_energy_finance_battery_day_savings') || ecoVal('sensor.smart_energy_finance_battery_day_discharge_value');
    var batteryMonth=ecoVal('sensor.smart_energy_finance_battery_month_savings') || ecoVal('sensor.smart_energy_finance_battery_month_discharge_value');
    var batteryYear=ecoVal('sensor.smart_energy_finance_battery_year_savings') || ecoVal('sensor.smart_energy_finance_battery_year_discharge_value');
    var solarDay=Math.max(0,day-batteryDay);
    var solarMonth=Math.max(0,month-batteryMonth);
    var solarYear=Math.max(0,year-batteryYear);
    var subDay=ecoVal('sensor.smart_energy_finance_day_subscription_cost');
    var subMonth=ecoVal('sensor.smart_energy_finance_month_subscription_cost') || (subDay*dayOfMonth());
    var subYear=ecoVal('sensor.smart_energy_finance_year_subscription_cost') || (subMonth*monthOfYear());
    var importDay=ecoVal('sensor.smart_energy_finance_day_import_cost');
    var exportDay=ecoVal('sensor.smart_energy_finance_day_export_revenue');
    var importMonth=ecoVal('sensor.smart_energy_finance_month_import_cost');
    var exportMonth=ecoVal('sensor.smart_energy_finance_month_export_revenue');
    var importYear=ecoVal('sensor.smart_energy_finance_year_import_cost');
