    setTxt('year_total',fmt(year,2));
    setTxt('day_solar_value',fmt(solarDay,2));
    setTxt('day_battery_value',fmt(batteryDay,2));
    setTxt('month_solar_value',fmt(solarMonth,2));
    setTxt('battery_month_savings',fmt(batteryMonth,2));
    setTxt('year_solar_value',fmt(solarYear,2));

    setEcoDonut('donut_day',[importDay,exportDay,solarDay,batteryDay,subDay]);
    setEcoDonut('donut_month',[Math.max(0,importMonth),Math.max(0,exportMonth),Math.max(0,solarMonth),Math.max(0,batteryMonth),Math.max(0,subMonth)]);
    setEcoDonut('donut_year',[Math.max(0,importYear),Math.max(0,exportYear),Math.max(0,solarYear),Math.max(0,batteryYear),Math.max(0,subYear)]);

    if(typeof donutLabels==='function'){
      donutLabels('donut_month',[
        {v:solarMonth,c:'#ffc928',label:'solaire',pos:'top'},
        {v:batteryMonth,c:'#24e06d',label:'batterie',pos:'right'},
        {v:month,c:'#38bdf8',label:'total',pos:'left'}
      ]);
      donutLabels('donut_year',[
        {v:solarYear,c:'#ffc928',label:'solaire',pos:'top'},
        {v:batteryYear,c:'#24e06d',label:'batterie',pos:'right'},
        {v:year,c:'#38bdf8',label:'total',pos:'left'}
      ]);
    }

    window.renderMonthSplit();
    window.renderHistory();
    return r;
  };

  setTimeout(function(){ try{ if(typeof window.updateFinance==='function') window.updateFinance(); }catch(e){} },300);
})();
