  function fmt(v,d){return n(v).toFixed(d===undefined?2:d)}
  function st(id){return (window.STATES&&window.STATES[id])?window.STATES[id].state:undefined}
  function ecoVal(id){return n(st(id))}
  function removeDonutBoxes(){document.querySelectorAll('.donut-label,.donut-hover-svg,.sef-donut-tip').forEach(function(x){x.remove()})}
  function dayOfMonth(){return new Date().getDate()}
