function ensureDir(dir) {
  fs.mkdirSync(dir, { recursive: true });
  fs.accessSync(dir, fs.constants.W_OK);
  return dir;
}

function exists(file) {
  try { return fs.existsSync(file); } catch (e) { return false; }
}

function read(file) {
  return fs.readFileSync(file, "utf8");
}

function writeFileSafe(file, content) {
  fs.mkdirSync(path.dirname(file), { recursive: true });
  fs.writeFileSync(file, content, "utf8");
}

function patchIndex(file, financeUrl) {
  if (!exists(file)) return false;

  let html = read(file);
  let changed = false;
  const VERSION = "71";

  function markChanged(before) {
    if (html !== before) changed = true;
  }

  function addBridge() {
    // Supprime les anciens bridges SEF pour éviter plusieurs listeners.
    const beforeClean = html;
    html = html.replace(/<script id="SEF_HASS_STATES_BRIDGE_V\d+">[\s\S]*?</script>/g, "");
    markChanged(beforeClean);

    if (html.includes("SEF_HASS_STATES_BRIDGE_V71")) return;

    const bridge = `<script id="SEF_HASS_STATES_BRIDGE_V71">
window.addEventListener('message',function(ev){
  if(!ev.data || ev.data.type!=='SEF_REQUEST_HASS_STATES') return;
  try {
    var ha=document.querySelector('home-assistant');
    var hass=(window.hass)||(ha&&ha.hass);
    if(hass&&hass.states) ev.source.postMessage({type:'SEF_HASS_STATES',states:hass.states},'*');
  } catch(e) {}
});
</script>`;

    if (html.includes("</body>")) html = html.replace("</body>", bridge + "</body>");
    else html += bridge;
    changed = true;
  }

  function hasFinanceInMenuOrModules() {
    return /showTab\(['"]finance['"]/.test(html) ||
           /data-view=["']finance["']/.test(html) ||
           /data-module=["']finance["']/.test(html) ||
           /id\s*:\s*['"]finance['"]/.test(html) ||
           /finance\.html/i.test(html) && /Smart Energy|JK-BMS|Voltronic/i.test(html);
  }

  function addFinanceToSharedModules() {
    // Cas du shell JK seul : le menu est généré depuis const modules=[...]
    // Important : Finance ne doit jamais être inséré en premier, sinon le scan périodique remet Finance actif.
    if (!/(const|let|var)\s+modules\s*=\s*\[/.test(html)) return;

    const before = html;
    const financeModule = `{id:'finance',label:'💶 Finance',url:'finance.html'}`;

    // Supprime toute ancienne insertion Finance, surtout si elle avait été mise en première position.
    html = html.replace(/\{\s*id\s*:\s*['"]finance['"][^}]*\}\s*,?/g, "");

    // Patch direct du shared index JK généré par le noeud PATCH/CREATE SHARED INDEX.
    // Ce cas utilise: const modules=[{id:'jk',label:T.jk,url:'jkbms.html'}, ...]
    html = html.replace(/const\s+modules\s*=\s*\[\s*\{id:['"]jk['"],label:T\.jk,url:['"]jkbms\.html['"]\}\s*,?/, function(m){
      return m.replace(/,?\s*$/, '') + `,${financeModule},`;
    });

    // Réinsère Finance juste après JK-BMS si le module JK est présent.
    if (!/id\s*:\s*['"]finance['"]/.test(html) && /\{\s*id\s*:\s*['"]jk['"][^}]*\}/.test(html)) {
      html = html.replace(
        /(\{\s*id\s*:\s*['"]jk['"][^}]*\}\s*,?)/,
        `$1${financeModule},`
      );
    } else if (!/id\s*:\s*['"]finance['"]/.test(html)) {
      // Fallback : fin du tableau modules, mais jamais au début.
      html = html.replace(/((const|let|var)\s+modules\s*=\s*\[[\s\S]*?)(\]\s*;)/, `$1,${financeModule}$3`);
    }

    markChanged(before);
  }

  function keepCurrentModuleOnSharedScan() {
    // Le shell JK rescane les modules toutes les 15 s.
    // Avant, à chaque scan il ouvrait le premier module trouvé, donc Finance pouvait reprendre la main.
    let before = html;

    if (!html.includes("smart_energy_active_module")) {
      html = html.replace(
        /function\s+open\(m,b\)\s*\{/,
        "function open(m,b){try{localStorage.setItem('smart_energy_active_module',m.id)}catch(e){}"
      );
    }

    html = html.replace(
      /if\(i===0\)setTimeout\(\(\)=>open\(m,b\),0\)/g,
      "if((localStorage.getItem('smart_energy_active_module')||found[0].id)===m.id)setTimeout(()=>open(m,b),0)"
    );

    markChanged(before);
  }

  function addFinanceToMainNav() {
    if (/showTab\(['"]finance['"]/.test(html)) return;

    const btn = `<button class="tab" onclick="showTab('finance',this)">💶 Finance</button>`;

    if (html.includes('id="main_nav"')) {
      const before = html;

      // 1) insertion juste après JK-BMS si présent
      html = html.replace(
        /(<button (?=[^>]*onclick=["']showTab\(["']jkbms["'])[^>]*>[\s\S]*?</button>)/,
        `$1${btn}`
      );

      // 2) sinon à la fin du main_nav
      if (html === before) {
        html = html.replace(
          /(<div [^>]*id=["']main_nav["'][^>]*>[\s\S]*?)(</div>\s*</aside>)/,
          (m, nav, end) => nav + btn + end
        );
      }

      markChanged(before);
    }
  }

  function addFinanceToDataModuleShell() {
    // Cas Voltronic nouveau shell: boutons data-module + iframe frame_finance.
    if (!html.includes('data-module') && !html.includes('module-frame')) return;

    let before = html;

    if (!/data-module=["']finance["']/.test(html) && html.includes('id="main_nav"')) {
      const btn = `<button class="tab" data-module="finance" data-view="finance" data-title="Smart Energy Finance" data-url="${financeUrl}">💶 Finance</button>`;
      html = html.replace(
        /(<div [^>]*id=["']main_nav["'][^>]*>[\s\S]*?)(</div>\s*</aside>)/,
        (m, nav, end) => nav + btn + end
      );
    }

    if (!/id=["']frame_finance["']/.test(html) && html.includes('class="framewrap"')) {
      html = html.replace(
        /(<div [^>]*class=["'][^"']*framewrap[^"']*["'][^>]*>)/,
        `$1
      <iframe id="frame_finance" class="module-frame" data-module="finance" src="about:blank"></iframe>`
      );
    }

    // Si le JS a une map frames={...}, ajouter finance dedans si absent.
    if (/const\s+frames\s*=\s*\{/.test(html) && !/finance\s*:\s*document\.getElementById\(['"]frame_finance['"]\)/.test(html)) {
      html = html.replace(/(const\s+frames\s*=\s*\{)/, `$1
    finance:document.getElementById('frame_finance'),`);
    }

    markChanged(before);
  }

  function addFinanceToHouseMenu() {
    if (!html.includes('class="menu"') && !html.includes('pageView')) return;

    let before = html;

    if (!/data-view=["']finance["']/.test(html)) {
      html = html.replace(
        /(<nav [^>]*class=["'][^"']*menu[^"']*["'][^>]*>[\s\S]*?)(</nav>)/,
        (m, nav, end) => nav + `<button class="houseModuleBtn" data-view="finance" data-module-url="${financeUrl}"><span class="ico">💶</span>Finance</button>` + end
      );
    }

    if (!html.includes('pageFinance') && html.includes('</main>')) {
      html = html.replace(
        '</main>',
        `<section class="pageView pageFinance houseModulePage"><iframe id="houseFinanceFrame" title="Finance" src="${financeUrl}?embed=1&v=69"></iframe></section>
</main>`
      );
    }

    if (html.includes('.main.view-inverters') && !html.includes('view-finance')) {
      html = html.replace(
        '.main.view-inverters .pageInverters,main.view-energy .pageEnergy',
        '.main.view-inverters .pageInverters,main.view-energy .pageEnergy,main.view-finance .pageFinance'
      );
    }

    markChanged(before);
  }

  function addFinanceSectionForShowTab() {
    // Cas JK ancien: showTab + sections .view
    if (!/function\s+showTab\s*\(/.test(html)) return;

    const iframe = `<section id="finance" class="view"><iframe id="financeFrame" title="Finance" src="${financeUrl}?embed=1&v=69" style="width:100%;height:calc(100vh - 80px);border:0;border-radius:18px;background:#06111f"></iframe></section>`;

    if (!/<section [^>]*id=["']finance["']/.test(html) && html.includes("</main>")) {
      const before = html;
      html = html.replace("</main>", iframe + "
</main>");
      markChanged(before);
    } else if (/<section [^>]*id=["']finance["']/.test(html)) {
      const before = html;
      html = html.replace(/src=["'][^"']*finance\.html[^"']*["']/g, `src="${financeUrl}?embed=1&v=69"`);
      markChanged(before);
    }
  }

  function removeJkOnlyModeWhenFinanceExists() {
    // Le shell JK seul cache le menu/header avec body.module-jk-only.
    // Dès qu'un deuxième module est ajouté, il ne doit plus être en mode module unique.
    if (/id\s*:\s*['"]finance['"]/.test(html) || /showTab\(['"]finance['"]/.test(html) || /data-module=["']finance["']/.test(html)) {
      const before = html;
      html = html.replace(/<body\s+class=["']module-jk-only["']>/, '<body>');
      markChanged(before);
    }
  }

  addBridge();
  addFinanceToSharedModules();
  keepCurrentModuleOnSharedScan();
  addFinanceToDataModuleShell();
  addFinanceToMainNav();
  addFinanceToHouseMenu();
  addFinanceSectionForShowTab();
  removeJkOnlyModeWhenFinanceExists();

  if (changed) writeFileSafe(file, html);
  return changed;
}

