<script id="SEF_STANDALONE_HASS_BRIDGE_V69">
window.addEventListener('message',function(ev){
  if(!ev.data || ev.data.type!=='SEF_REQUEST_HASS_STATES') return;
  try{
    var wins=[window,window.parent,window.top];
    for(var i=0;i<wins.length;i++){
      var w=wins[i];
      var ha=w.document&&w.document.querySelector&&w.document.querySelector('home-assistant');
      var hass=(w.hass)||(ha&&ha.hass);
