try {
  // IMPORTANT : selon le mapping HA Add-on, le dossier www peut être exposé
  // sous /config, /homeassistant ou /homeassistant_config.
  // On garde /config en premier, mais on essaye tous les chemins possibles.
  const dirs = [
    "/config/www/smart-modular-dashboard",
    "/homeassistant/www/smart-modular-dashboard",
    "/homeassistant_config/www/smart-modular-dashboard"
  ];
  const houseDirs = [
    "/config/www/smart-modular-dashboard-house",
    "/homeassistant/www/smart-modular-dashboard-house",
    "/homeassistant_config/www/smart-modular-dashboard-house"
  ];

  const standardUrl = "/local/smart-modular-dashboard/finance.html";
  const houseUrl = "/local/smart-modular-dashboard-house/finance.html";

  const targets = [
    ...dirs.map(dir => ({ dir, url: standardUrl, kind: "standard_or_jk" })),
    ...houseDirs.map(dir => ({ dir, url: houseUrl, kind: "house" }))
  ];

  let written = [];
  let patched = 0;
  let integrated = [];

  // On considère comme dashboard existant seulement un index modulaire réel.
  function isExistingModularIndex(file) {
    if (!exists(file)) return false;
    try {
      const h = read(file);
      return /jkbms\.html|voltronic\.html|frame_jkbms|frame_voltronic|showTab\(['"]jkbms['"]|id=["']main_nav["']|const\s+modules\s*=\s*\[/i.test(h);
    } catch(e) {
      return false;
    }
  }

  const existingTargets = targets.filter(t => isExistingModularIndex(path.join(t.dir, "index.html")));

  if (existingTargets.length > 0) {
    // On écrit finance.html dans tous les dossiers standard accessibles pour que le scan JK le trouve.
    for (const dir of dirs) {
      try {
        ensureDir(dir);
        writeFileSafe(path.join(dir, "finance.html"), financeHtml);
        written.push(path.join(dir, "finance.html"));
      } catch(e) {}
    }
    // Et dans House si son index existe.
    for (const dir of houseDirs) {
      try {
        if (exists(path.join(dir, "index.html"))) {
          ensureDir(dir);
          writeFileSafe(path.join(dir, "finance.html"), financeHtml);
          written.push(path.join(dir, "finance.html"));
        }
      } catch(e) {}
    }

    for (const t of existingTargets) {
      try {
        if (patchIndex(path.join(t.dir, "index.html"), t.url)) patched++;
        integrated.push(t.kind + ":" + t.dir);
      } catch(e) {
        node.warn("Patch index Finance ignoré pour " + t.dir + " : " + e.message);
      }
    }

    if (!written.length) throw new Error("dashboard modulaire trouvé mais finance.html non écrit");

    global.set("dashboard.finance_html_integrated_existing", true);
    global.set("dashboard.finance_html_standalone_needed", false);

    node.status({ fill:"green", shape:"dot", text:"finance v71 intégrée / patch=" + patched });
    msg.payload = { ok:true, version:71, mode:"integrated_existing", written, patched_indexes:patched, integrated };

    // Bloque le noeud iframe derrière : aucun dashboard Finance séparé.
    return null;
  }

  // Aucun dashboard modulaire existant : Finance crée son dashboard autonome.
  // On crée explicitement le dossier smart-modular-dashboard et un index.html minimal.
  const writeErrors = [];
  for (const dir of dirs) {
    try {
      ensureDir(dir);
      writeFileSafe(path.join(dir, "finance.html"), financeHtml);
      writeFileSafe(path.join(dir, "index.html"), standaloneIndex(standardUrl));
      written.push(path.join(dir, "finance.html"));
      written.push(path.join(dir, "index.html"));
      integrated.push("standalone:" + dir);
      // IMPORTANT : ne pas arrêter au premier dossier.
      // Sur certains add-ons, /config pointe vers addon_config,
      // alors que Home Assistant sert /homeassistant_config/www via /local.
      // On écrit donc dans TOUS les dossiers accessibles.
    } catch(e) {
      writeErrors.push(dir + " -> " + (e && e.message ? e.message : String(e)));
    }
  }

  if (!written.length) {
    node.warn("[Smart Energy Finance] Impossible de créer smart-modular-dashboard. Essais: " + writeErrors.join(" | "));
    throw new Error("aucun dossier www accessible pour smart-modular-dashboard");
  }

  global.set("dashboard.finance_html_integrated_existing", false);
  global.set("dashboard.finance_html_standalone_needed", true);

  node.status({ fill:"green", shape:"dot", text:"finance v71 standalone + index prêt" });
  msg.payload = { ok:true, version:71, mode:"standalone", written, patched_indexes:patched, integrated };
  return msg;
} catch(e) {
  node.status({ fill:"red", shape:"ring", text:"erreur finance v71" });
  node.error("Erreur génération Finance HTML v71 : " + e.message, msg);
  return null;
}

function getPremiumDashboardOutput() {
    const opts = global.get("addon_config") || global.get("options") || {};
    const raw = String(
        global.get("config.premiumDashboardOutput") ||
        global.get("premium.dashboard_output") ||
        global.get("premiumDashboardOutput") ||
        opts.premium_dashboard_output ||
        opts.dashboard_output ||
        env.get("PREMIUM_DASHBOARD_OUTPUT") ||
        "html"
    ).toLowerCase().trim();

    const allowed = ["lovelace", "html", "both", "disabled"];
    return allowed.includes(raw) ? raw : "html";
}

const premiumDashboardOutput = getPremiumDashboardOutput();

if (premiumDashboardOutput !== "html" && premiumDashboardOutput !== "both") {
    node.status({
        fill: "blue",
        shape: "ring",
        text: `mode ${premiumDashboardOutput} -> iframe ignoré`
    });
    return null;
}

/*
 IMPORTANT :
 - Si Finance s'est intégré dans JK/Voltronic/House, le nœud HTML retourne null,
   donc ce nœud n'est pas appelé.
 - Si ce nœud reçoit un msg, c'est le mode standalone.
 - On pointe vers index.html, créé par BUILD MODULAR HTML DASHBOARD FINANCE,
   et index.html charge ensuite finance.html.
*/

const dashboardLangRaw = String(
    global.get("config.dashboardLanguage") ||
    global.get("dashboard.language") ||
    global.get("dashboardLanguage") ||
    env.get("DASHBOARD_LANGUAGE") ||
    "en"
).trim().toLowerCase();

const isFr = dashboardLangRaw.startsWith("fr");
const title = isFr ? "Smart Energy Finance Premium" : "Smart Energy Finance Premium";
const iframeUrl = "/local/smart-modular-dashboard/index.html?standalone=1&v=" + Date.now();

const dashboardJson = {
    dashboard_meta: {
        url_path: "smart-energy-finance-premium",
        title,
        icon: "mdi:cash-multiple",
        show_in_sidebar: true,
        require_admin: false
    },
    config: {
        title,
        views: [
            {
                title,
                path: "home",
                icon: "mdi:cash-multiple",
                panel: true,
                cards: [
                    {
                        type: "iframe",
                        url: iframeUrl,
                        aspect_ratio: "100%"
                    }
                ]
            }
        ]
    }
};

msg.filename = "/config/dashboards/smart_energy_finance_premium.json";
msg.payload = JSON.stringify(dashboardJson, null, 2);

node.status({
    fill: "green",
    shape: "dot",
    text: "iframe Finance standalone -> index.html"
});

return msg;

const inputEnv = msg.payload.toString().trim();

let configPath;
let statusColor;
let bip;

switch(inputEnv) {
    case 'HAOS':
        configPath = '/data/options.json';
        msg.environment = 'Home Assistant OS';
        bip = 1;
        statusColor = 'green';
        break;
    case 'Docker':
        configPath = '/data/options.json';
        msg.environment = 'Docker (autre)';
        bip = 2;
        statusColor = 'blue';
        break;
    case 'Linux':
        configPath = '/data/options.json';
        msg.environment = 'Linux barebone';
        bip = 3;
        statusColor = 'yellow';
        break;
    case 'Windows':
        configPath = 'C:\\data\\options.json';
        msg.environment = 'Windows';
        bip = 4;
        statusColor = 'purple';
        break;
    default:
        configPath = './data/options.json';
        msg.environment = 'Inconnu';
        bip = 5;
        statusColor = 'red';
}

// 2ème digit : premium actif ou non
const premium = global.get('premium') || {};
const premiumDigit = (premium.status === 'active') ? '1' : '0';

msg.filename = configPath;
msg.payload = { "bip": String(bip) + premiumDigit };  // ex: "11", "10", "21"...
msg.headers = { "Content-Type": "application/json" };
node.status({fill: statusColor, shape: "dot", text: msg.environment});
return msg;
